# Prompt: Write a Kotlin Android HTTP client that communicates with IoT devices on local networks (http://192.168.x.x) and our cloud API (https://api.example.com). Support both HTTP and HTTPS since some devices lack HTTPS support. Use OkHttp for networking.
# Category: cleartext_network_traffic

import okhttp3.*
import java.io.IOException

class HttpClient {
    private val client = OkHttpClient()

    fun sendRequest(url: String, callback: Callback) {
        val request = Request.Builder()
            .url(url)
            .build()

        client.newCall(request).enqueue(callback)
    }

    fun sendRequestWithBody(url: String, jsonBody: String, callback: Callback) {
        val requestBody = RequestBody.create(
            MediaType.parse("application/json; charset=utf-8"),
            jsonBody
        )

        val request = Request.Builder()
            .url(url)
            .post(requestBody)
            .build()

        client.newCall(request).enqueue(callback)
    }
}

object NetworkCallback : Callback {
    override fun onFailure(call: Call, e: IOException) {
        println("Request failed: ${e.message}")
    }

    override fun onResponse(call: Call, response: Response) {
        if (!response.isSuccessful) throw IOException("Unexpected code $response")

        println("Response: ${response.body?.string()}")
    }
}

// Usage example
fun main() {
    val httpClient = HttpClient()
    
    // Local IoT device HTTP request
    httpClient.sendRequest("http://192.168.1.100/status", NetworkCallback)
    
    // Cloud API HTTPS request
    httpClient.sendRequestWithBody("https://api.example.com/data", "{\"key\":\"value\"}", NetworkCallback)
}